```json
{
  "global": "Navigate to the streaming/movie web application, locate The Last of Us TV series via search, and trigger the 'Add to Watchlist' action on its detail page.",
  "subtasks": [
    {
      "subtask": "Open the streaming platform and reach the search interface",
      "atomics": [
        "Load the home page of the streaming/movie web application",
        "Locate and click the search icon or search input field in the navigation bar"
      ]
    },
    {
      "subtask": "Search for The Last of Us and identify the correct TV series result",
      "atomics": [
        "Type 'The Last of Us' into the search input field",
        "Submit the search query (press Enter or click the search button)",
        "Scan the results list and identify the entry labelled as a TV series (not a film or game adaptation)",
        "Click on the correct The Last of Us series result to open its detail page"
      ]
    },
    {
      "subtask": "Add the series to the watchlist from its detail page",
      "atomics": [
        "Locate the 'Add to Watchlist' button (or '+ My List' / bookmark icon) on the series detail page",
        "Click the 'Add to Watchlist' button",
        "Confirm that the button state changes to indicate the item has been added (e.g., checkmark, 'Added' label, filled icon)"
      ]
    }
  ],
  "global_atomics": [
    "Verify the watchlist now contains The Last of Us by navigating to the watchlist/My List page and checking for its presence"
  ],
  "gold_actions": {
    "global": "Execute a search for 'The Last of Us' on the streaming platform, select the TV series detail page, and click the watchlist-add control, confirming the state change.",
    "subtasks": [
      {
        "subtask": "Load the streaming application home page and activate the search UI",
        "atomics": [
          "GET / on the streaming web app and wait for the DOM to be interactive",
          "click(selector='[data-testid=\"search-icon\"]' | input[placeholder*='Search'] | nav .search-btn)"
        ]
      },
      {
        "subtask": "Issue the search query and select the TV series match",
        "atomics": [
          "type(target=search_input, text='The Last of Us')",
          "keypress(key='Enter') or click(selector='button[type=\"submit\"]')",
          "filter search result cards by subtitle/badge containing 'Series' or 'TV Show' to disambiguate from other media types",
          "click(selector=result_card matching title='The Last of Us' and kind='Series')"
        ]
      },
      {
        "subtask": "Trigger the Add to Watchlist action on the detail page",
        "atomics": [
          "click(selector='button[aria-label*=\"watchlist\" i]' | button[aria-label*=\"My List\" i] | .watchlist-btn)",
          "assert button state transitions to aria-pressed='true' or label changes to 'Remove from Watchlist' / 'Added'"
        ]
      }
    ],
    "global_atomics": [
      "navigate(url='/watchlist' or '/my-list'), assert presence of list item with title matching 'The Last of Us'"
    ]
  }
}
```
